scriptBlocks.content:
function init()
{
    var barcolors = new Array('#F68C47', '#FFD400', '#BD73B0', '#94D6DA');
    @{
        string colorBandFormat = "";
        string tempStart = "";
        string tempEnd = "";
    }
        @if (timeTables.Count() > 0)
        {
            foreach (BusTimeTable timeTableItem in timeTables)
            {
                for (int dayType = 1; dayType <= 4; dayType++)
                {
                    string arrayItem = "";
                    @Html.Raw("var barfirsthaft" + timeTableItem.Dir + dayType.ToString() + " = new Array(")

                    if (!string.IsNullOrEmpty(timeTableItem.ColorBand[dayType - 1]))
                    {
                        xmlDoc.LoadXml(timeTableItem.ColorBand[dayType - 1].Trim()); // Load the XML document from the specified file
                        XmlNodeList timeList = xmlDoc.SelectNodes("//svcheadway");
                        if (timeList != null)
                        {
                            int loop2 = 1;

                            foreach (XmlNode item1 in timeList)
                            {
                                colorBandFormat = controller.GetBusTimeColor(item1.SelectSingleNode("colorband").InnerText);
                                tempStart = item1.SelectSingleNode("starttime").InnerText;
                                tempEnd = item1.SelectSingleNode("endtime").InnerText;
                                //if (loop2 > 5)
                                {
                                    tempEnd = controller.RevertTime(tempEnd);
                                    tempStart = controller.RevertTime(tempStart);
                                }

                                string[] parserTimeStart = tempStart.Split(':');
                                string[] parserTimeEnd = tempEnd.Split(':');
                                arrayItem += "{ from: \"" + tempStart + "\", to: \"" + tempEnd + "\", color: \"" + colorBandFormat + "\"},\n";

                                loop2++;
                            }
                        }
                    }
                    if (arrayItem.Length > 3)
                    {
                        arrayItem = arrayItem.Substring(0, arrayItem.Length - 2);
                    }


                    @Html.Raw(arrayItem + "); \n //------loop 2-------------- \n")
                //@Html.Raw("drawStackedBarNoTime('barfirsthaft" + timeTableItem.Dir + dayType.ToString()  + "', new Array(\"" + timeTableItem.FirstTime[dayType - 1] + "\", \"" + timeTableItem.LastTime[dayType - 1] + "\"), barfirsthaft" + timeTableItem.Dir + dayType.ToString() + ", barcolors);");
            }

            for (int dayType = 1; dayType <= 4; dayType++)
            {
                @Html.Raw("var barlasthaft" + timeTableItem.Dir + dayType.ToString() + " = new Array(")

                    if (!string.IsNullOrEmpty(timeTableItem.ColorBand[dayType - 1]))
                    {
                        xmlDoc.LoadXml(timeTableItem.ColorBand[dayType - 1].Trim()); // Load the XML document from the specified file
                        XmlNodeList timeList = xmlDoc.SelectNodes("//svcheadway");
                        if (timeList != null)
                        {
                            int loop3 = 1;
                            foreach (XmlNode item1 in timeList)
                            {
                                colorBandFormat = controller.GetBusTimeColor(item1.SelectSingleNode("colorband").InnerText);
                                tempStart = item1.SelectSingleNode("starttime").InnerText;
                                tempEnd = item1.SelectSingleNode("endtime").InnerText;
                                //if (loop3 > 5)
                                {
                                    tempEnd = controller.RevertTime(tempEnd);
                                    tempStart = controller.RevertTime(tempStart);
                                }

                                string[] parserTimeStart = tempStart.Split(':');
                                string[] parserTimeEnd = tempEnd.Split(':');
                                if (Convert.ToInt32(parserTimeStart[0]) < 15 && Convert.ToInt32(parserTimeEnd[0]) >= 15)
                                {
                                    tempStart = "15:01";
                                    if (loop3 < timeList.Count)
                                    {
                                    @Html.Raw("{ from: \"" + tempStart + "\", to: \"" + tempEnd + "\", color: \"" + colorBandFormat + "\"}, \n");
                                }
                                else
                                {
                                    @Html.Raw("{ from: \"" + tempStart + "\", to: \"" + tempEnd + "\", color: \"" + colorBandFormat + "\"} \n");
                                }
                            }
                            else if (Convert.ToInt32(parserTimeStart[0]) >= 15)
                            {
                                if (loop3 < timeList.Count)
                                {
                                    @Html.Raw("{ from: \"" + tempStart + "\", to: \"" + tempEnd + "\", color: \"" + colorBandFormat + "\"}, \n");
                                }
                                else
                                {
                                    @Html.Raw("{ from: \"" + tempStart + "\", to: \"" + tempEnd + "\", color: \"" + colorBandFormat + "\"} \n");
                                }
                            }
                            loop3++;
                        }
                    }
                }
                @Html.Raw("); \n //------loop 3-------------- \n")
                @Html.Raw("barfirsthaft" + timeTableItem.Dir + dayType.ToString() + " = barfirsthaft" + timeTableItem.Dir + dayType.ToString() + ".length > 0 ? barfirsthaft" + timeTableItem.Dir + dayType.ToString() + " : barlasthaft" + timeTableItem.Dir + dayType.ToString() + ";");
                @Html.Raw("drawStackedBarNoTime('barfirsthaft" + timeTableItem.Dir + dayType.ToString()  + "popup', new Array(\"" + timeTableItem.FirstTime[dayType - 1] + "\", \"" + timeTableItem.LastTime[dayType - 1] + "\"), barfirsthaft" + timeTableItem.Dir + dayType.ToString() + ", barcolors);");
                @Html.Raw("drawStackedBarNoTime('barlasthaft" + timeTableItem.Dir + dayType.ToString()  + "popup', new Array(\"" + timeTableItem.FirstTime[dayType - 1] + "\", \"" + timeTableItem.LastTime[dayType - 1] + "\"), barlasthaft" + timeTableItem.Dir + dayType.ToString() + ", barcolors); \n");

            }
        }
    }
}

